   188→// markUpdatedPodsReady manually marks updated Deployment pods status to ready,
   189→// until the deployment is complete
   190→func (d *deploymentTester) markUpdatedPodsReady(wg *sync.WaitGroup) {
   191→	defer wg.Done()
   192→
   193→	ns := d.deployment.Namespace
   194→	err := wait.PollImmediate(pollInterval, pollTimeout, func() (bool, error) {
   195→		// We're done when the deployment is complete
   196→		if completed, err := d.deploymentComplete(); err != nil {
   197→			return false, err
   198→		} else if completed {
   199→			return true, nil
   200→		}
   201→		// Otherwise, mark remaining pods as ready
   202→		pods, err := d.listUpdatedPods()
   203→		if err != nil {
   204→			d.t.Log(err)
   205→			return false, nil
   206→		}
   207→		d.t.Logf("%d/%d of deployment pods are created", len(pods), *d.deployment.Spec.Replicas)
   208→		for i := range pods {
   209→			pod := pods[i]
   210→			if podutil.IsPodReady(&pod) {
   211→				continue
   212→			}
   213→			if err = markPodReady(d.c, ns, &pod); err != nil {
   214→				d.t.Logf("failed to update Deployment pod %s, will retry later: %v", pod.Name, err)
   215→			}
   216→		}
   217→		return false, nil
   218→	})
   219→	if err != nil {
   220→		d.t.Errorf("failed to mark updated Deployment pods to ready: %v", err)
   221→	}
   222→}
