   399→func (d *deploymentTester) listUpdatedPods() ([]v1.Pod, error) {
   400→	selector, err := metav1.LabelSelectorAsSelector(d.deployment.Spec.Selector)
   401→	if err != nil {
   402→		return nil, fmt.Errorf("failed to parse deployment selector: %v", err)
   403→	}
   404→	pods, err := d.c.CoreV1().Pods(d.deployment.Namespace).List(context.TODO(), metav1.ListOptions{LabelSelector: selector.String()})
   405→	if err != nil {
   406→		return nil, fmt.Errorf("failed to list deployment pods, will retry later: %v", err)
   407→	}
   408→	newRS, err := d.getNewReplicaSet()
   409→	if err != nil {
   410→		return nil, fmt.Errorf("failed to get new replicaset of deployment %q: %v", d.deployment.Name, err)
   411→	}
   412→	if newRS == nil {
   413→		return nil, fmt.Errorf("unable to find new replicaset of deployment %q", d.deployment.Name)
   414→	}
   415→
   416→	var ownedPods []v1.Pod
   417→	for _, pod := range pods.Items {
   418→		rs := metav1.GetControllerOf(&pod)
   419→		if rs.UID == newRS.UID {
   420→			ownedPods = append(ownedPods, pod)
   421→		}
   422→	}
   423→	return ownedPods, nil
   424→}
