   105→// dcSetup sets up necessities for Deployment integration test, including control plane, apiserver, informers, and clientset
   106→func dcSetup(ctx context.Context, t *testing.T) (kubeapiservertesting.TearDownFunc, *replicaset.ReplicaSetController, *deployment.DeploymentController, informers.SharedInformerFactory, clientset.Interface) {
   107→	// Disable ServiceAccount admission plugin as we don't have serviceaccount controller running.
   108→	server := kubeapiservertesting.StartTestServerOrDie(t, nil, framework.DefaultTestServerFlags(), framework.SharedEtcd())
   109→
   110→	config := restclient.CopyConfig(server.ClientConfig)
   111→	clientSet, err := clientset.NewForConfig(config)
   112→	if err != nil {
   113→		t.Fatalf("error in create clientset: %v", err)
   114→	}
   115→	resyncPeriod := 12 * time.Hour
   116→	informers := informers.NewSharedInformerFactory(clientset.NewForConfigOrDie(restclient.AddUserAgent(config, "deployment-informers")), resyncPeriod)
   117→
   118→	dc, err := deployment.NewDeploymentController(
   119→		ctx,
   120→		informers.Apps().V1().Deployments(),
   121→		informers.Apps().V1().ReplicaSets(),
   122→		informers.Core().V1().Pods(),
   123→		clientset.NewForConfigOrDie(restclient.AddUserAgent(config, "deployment-controller")),
   124→	)
   125→	if err != nil {
   126→		t.Fatalf("error creating Deployment controller: %v", err)
   127→	}
   128→	rm := replicaset.NewReplicaSetController(
   129→		ctx,
   130→		informers.Apps().V1().ReplicaSets(),
   131→		informers.Core().V1().Pods(),
   132→		clientset.NewForConfigOrDie(restclient.AddUserAgent(config, "replicaset-controller")),
   133→		replicaset.BurstReplicas,
   134→	)
   135→	return server.TearDownFn, rm, dc, informers, clientSet
   136→}
