   263→// Waits for the deployment to complete, and check rolling update strategy isn't broken at any times.
   264→// Rolling update strategy should not be broken during a rolling update.
   265→func (d *deploymentTester) waitForDeploymentCompleteAndCheckRolling() error {
   266→	return testutil.WaitForDeploymentCompleteAndCheckRolling(d.c, d.deployment, d.t.Logf, pollInterval, pollTimeout)
   267→}
   268→
   269→// Waits for the deployment to complete, and don't check if rolling update strategy is broken.
   270→// Rolling update strategy is used only during a rolling update, and can be violated in other situations,
   271→// such as shortly after a scaling event or the deployment is just created.
   272→func (d *deploymentTester) waitForDeploymentComplete() error {
   273→	return testutil.WaitForDeploymentComplete(d.c, d.deployment, d.t.Logf, pollInterval, pollTimeout)
   274→}
   275→
   276→// waitForDeploymentCompleteAndCheckRollingAndMarkPodsReady waits for the Deployment to complete
   277→// while marking updated Deployment pods as ready at the same time.
   278→// Uses hard check to make sure rolling update strategy is not violated at any times.
   279→func (d *deploymentTester) waitForDeploymentCompleteAndCheckRollingAndMarkPodsReady() error {
   280→	var wg sync.WaitGroup
   281→
   282→	// Manually mark updated Deployment pods as ready in a separate goroutine
   283→	wg.Add(1)
   284→	go d.markUpdatedPodsReady(&wg)
   285→	// Wait for goroutine to finish, for all return paths.
   286→	defer wg.Wait()
   287→
   288→	// Wait for the Deployment status to complete while Deployment pods are becoming ready
   289→	err := d.waitForDeploymentCompleteAndCheckRolling()
   290→	if err != nil {
   291→		return fmt.Errorf("failed to wait for Deployment %s to complete: %v", d.deployment.Name, err)
   292→	}
   293→
   294→	return nil
   295→}
   296→
   297→// waitForDeploymentCompleteAndMarkPodsReady waits for the Deployment to complete
   298→// while marking updated Deployment pods as ready at the same time.
   299→func (d *deploymentTester) waitForDeploymentCompleteAndMarkPodsReady() error {
   300→	var wg sync.WaitGroup
   301→
   302→	// Manually mark updated Deployment pods as ready in a separate goroutine
   303→	wg.Add(1)
   304→	go d.markUpdatedPodsReady(&wg)
   305→
   306→	// Wait for the Deployment status to complete using soft check, while Deployment pods are becoming ready
   307→	err := d.waitForDeploymentComplete()
   308→	if err != nil {
   309→		return fmt.Errorf("failed to wait for Deployment status %s: %v", d.deployment.Name, err)
   310→	}
   311→
   312→	// Wait for goroutine to finish
   313→	wg.Wait()
   314→
   315→	return nil
   316→}
   317→
   318→// waitForDeploymentCompleteAndMarkPodsReadyAndRemoveTerminating waits for the Deployment to complete
   319→// while marking updated Deployment pods as ready and removes terminated pods at the same time.
   320→func (d *deploymentTester) waitForDeploymentCompleteAndMarkPodsReadyAndRemoveTerminated(ctx context.Context) error {
   321→	var wg sync.WaitGroup
   322→
   323→	// Manually mark updated Deployment pods as ready in a separate goroutine
   324→	wg.Add(1)
   325→	go d.markUpdatedPodsReady(&wg)
   326→
   327→	wg.Add(1)
   328→	go d.removeTerminatedPods(ctx, &wg)
   329→
   330→	// Wait for the Deployment status to complete using soft check, while Deployment pods are becoming ready
   331→	err := d.waitForDeploymentComplete()
   332→	if err != nil {
   333→		return fmt.Errorf("failed to wait for Deployment status %s: %w", d.deployment.Name, err)
   334→	}
   335→
   336→	// Wait for goroutine to finish
   337→	wg.Wait()
   338→
   339→	return nil
   340→}
