   491→// waitForReadyReplicas waits for number of ready replicas to equal number of replicas.
   492→func (d *deploymentTester) waitForDeploymentStatusReplicasFields(ctx context.Context, replicas, updatedReplicas, readyReplicas, availableReplicas, unavailableReplicas int32, terminatingReplicas *int32) error {
   493→	var lastErr error
   494→	err := wait.PollUntilContextTimeout(ctx, pollInterval, pollTimeout, true, func(_ context.Context) (bool, error) {
   495→		// do not pass ctx to checkDeploymentStatusReplicasFields (Deployments().Get) so we always obtain the latest error and not the one from deadline exceeded
   496→		lastErr = d.checkDeploymentStatusReplicasFields(replicas, updatedReplicas, readyReplicas, availableReplicas, unavailableReplicas, terminatingReplicas)
   497→		return lastErr == nil, nil
   498→	})
   499→	if err != nil {
   500→		return fmt.Errorf("%w: %w", lastErr, err)
   501→	}
   502→	return nil
   503→}
   504→
   505→// Verify all replicas fields of DeploymentStatus have desired count.
   506→// Immediately return an error when found a non-matching replicas field.
   507→func (d *deploymentTester) checkDeploymentStatusReplicasFields(replicas, updatedReplicas, readyReplicas, availableReplicas, unavailableReplicas int32, terminatingReplicas *int32) error {
   508→	deployment, err := d.c.AppsV1().Deployments(d.deployment.Namespace).Get(context.TODO(), d.deployment.Name, metav1.GetOptions{})
   509→	if err != nil {
   510→		return fmt.Errorf("failed to get deployment %q: %v", d.deployment.Name, err)
   511→	}
   512→	if deployment.Status.Replicas != replicas {
   513→		return fmt.Errorf("unexpected .replicas: expect %d, got %d", replicas, deployment.Status.Replicas)
   514→	}
   515→	if deployment.Status.UpdatedReplicas != updatedReplicas {
   516→		return fmt.Errorf("unexpected .updatedReplicas: expect %d, got %d", updatedReplicas, deployment.Status.UpdatedReplicas)
   517→	}
   518→	if deployment.Status.ReadyReplicas != readyReplicas {
   519→		return fmt.Errorf("unexpected .readyReplicas: expect %d, got %d", readyReplicas, deployment.Status.ReadyReplicas)
   520→	}
   521→	if deployment.Status.AvailableReplicas != availableReplicas {
