    91→
    92→func (f *controllerFetcher) periodicallyRefreshCache(ctx context.Context, period time.Duration) {
    93→	for {
    94→		select {
    95→		case <-ctx.Done():
    96→			return
    97→		case <-time.After(period):
    98→			keysToRefresh := f.scaleSubresourceCacheStorage.GetKeysToRefresh()
    99→			klog.V(5).InfoS("Starting to refresh entries in controllerFetchers scaleSubresourceCacheStorage")
   100→			for _, item := range keysToRefresh {
   101→				scale, err := f.scaleNamespacer.Scales(item.namespace).Get(context.TODO(), item.groupResource, item.name, metav1.GetOptions{})
   102→				f.scaleSubresourceCacheStorage.Refresh(item.namespace, item.groupResource, item.name, scale, err)
   103→			}
   104→			klog.V(5).InfoS("Finished refreshing entries in controllerFetchers scaleSubresourceCacheStorage", "refreshed", len(keysToRefresh))
   105→			f.scaleSubresourceCacheStorage.RemoveExpired()
   106→		}
   107→	}
   108→}
   109→
   110→func (f *controllerFetcher) Start(ctx context.Context, loopPeriod time.Duration) {
   111→	go f.periodicallyRefreshCache(ctx, loopPeriod)
   112→}
   113→
   114→// NewControllerFetcher returns a new instance of controllerFetcher
   115→func NewControllerFetcher(config *rest.Config, kubeClient kube_client.Interface, factory informers.SharedInformerFactory, betweenRefreshes, lifeTime time.Duration, jitterFactor float64) *controllerFetcher {
   116→	discoveryClient, err := discovery.NewDiscoveryClientForConfig(config)
   117→	if err != nil {
   118→		klog.ErrorS(err, "Could not create discoveryClient")
   119→		klog.FlushAndExit(klog.ExitFlushTimeout, 1)
   120→	}
   121→	resolver := scale.NewDiscoveryScaleKindResolver(discoveryClient)
   122→	restClient := kubeClient.CoreV1().RESTClient()
   123→	cachedDiscoveryClient := cacheddiscovery.NewMemCacheClient(discoveryClient)
   124→	mapper := restmapper.NewDeferredDiscoveryRESTMapper(cachedDiscoveryClient)
   125→	go wait.Until(func() {
   126→		mapper.Reset()
   127→	}, discoveryResetPeriod, make(chan struct{}))
   128→
   129→	informersMap := map[wellKnownController]cache.SharedIndexInformer{
   130→		daemonSet:             factory.Apps().V1().DaemonSets().Informer(),
   131→		deployment:            factory.Apps().V1().Deployments().Informer(),
   132→		replicaSet:            factory.Apps().V1().ReplicaSets().Informer(),
   133→		statefulSet:           factory.Apps().V1().StatefulSets().Informer(),
   134→		replicationController: factory.Core().V1().ReplicationControllers().Informer(),
   135→		job:                   factory.Batch().V1().Jobs().Informer(),
   136→		cronJob:               factory.Batch().V1().CronJobs().Informer(),
   137→	}
   138→
   139→	scaleNamespacer := scale.New(restClient, mapper, dynamic.LegacyAPIPathResolverFunc, resolver)
   140→	return &controllerFetcher{
   141→		scaleNamespacer:              scaleNamespacer,
   142→		mapper:                       mapper,
   143→		informersMap:                 informersMap,
   144→		scaleSubresourceCacheStorage: newControllerCacheStorage(betweenRefreshes, lifeTime, jitterFactor),
   145→	}
   146→}
   147→
   148→func getOwnerController(owners []metav1.OwnerReference, namespace string) *ControllerKeyWithAPIVersion {
   149→	for _, owner := range owners {
   150→		if owner.Controller != nil && *owner.Controller {
   151→			return &ControllerKeyWithAPIVersion{
   152→				ControllerKey: ControllerKey{
   153→					Namespace: namespace,
   154→					Kind:      owner.Kind,
   155→					Name:      owner.Name,
   156→				},
   157→				ApiVersion: owner.APIVersion,
   158→			}
   159→		}
   160→	}
   161→	return nil
   162→}
   163→
   164→func getParentOfWellKnownController(informer cache.SharedIndexInformer, controllerKey ControllerKeyWithAPIVersion) (*ControllerKeyWithAPIVersion, error) {
   165→	namespace := controllerKey.Namespace
   166→	name := controllerKey.Name
   167→	kind := controllerKey.Kind
   168→
   169→	obj, exists, err := informer.GetStore().GetByKey(namespace + "/" + name)
   170→	if err != nil {
   171→		return nil, err
   172→	}
   173→	if !exists {
   174→		return nil, fmt.Errorf("%s %s/%s does not exist", kind, namespace, name)
   175→	}
   176→	switch apiObj := obj.(type) {
   177→	case (*appsv1.DaemonSet):
   178→		return getOwnerController(apiObj.OwnerReferences, namespace), nil
   179→	case (*appsv1.Deployment):
   180→		return getOwnerController(apiObj.OwnerReferences, namespace), nil
   181→	case (*appsv1.StatefulSet):
   182→		return getOwnerController(apiObj.OwnerReferences, namespace), nil
   183→	case (*appsv1.ReplicaSet):
   184→		return getOwnerController(apiObj.OwnerReferences, namespace), nil
   185→	case (*batchv1.Job):
   186→		return getOwnerController(apiObj.OwnerReferences, namespace), nil
   187→	case (*batchv1.CronJob):
   188→		return getOwnerController(apiObj.OwnerReferences, namespace), nil
   189→	case (*corev1.ReplicationController):
   190→		return getOwnerController(apiObj.OwnerReferences, namespace), nil
   191→	}
   192→
   193→	return nil, errors.New("don't know how to read owner controller")
   194→}
   195→
   196→func (f *controllerFetcher) getParentOfController(ctx context.Context, controllerKey ControllerKeyWithAPIVersion) (*ControllerKeyWithAPIVersion, error) {
   197→	kind := wellKnownController(controllerKey.Kind)
   198→	informer, exists := f.informersMap[kind]
   199→	if exists {
   200→		return getParentOfWellKnownController(informer, controllerKey)
   201→	}
   202→
   203→	groupKind, err := controllerKey.groupKind()
   204→	if err != nil {
   205→		return nil, err
   206→	}
   207→
   208→	owner, err := f.getOwnerForScaleResource(ctx, groupKind, controllerKey.Namespace, controllerKey.Name)
   209→	if apierrors.IsNotFound(err) {
   210→		return nil, nil
   211→	}
   212→	if err != nil {
   213→		return nil, fmt.Errorf("unhandled targetRef %s / %s / %s, last error %w",
   214→			controllerKey.ApiVersion, controllerKey.Kind, controllerKey.Name, err)
   215→	}
   216→
   217→	return owner, nil
   218→}
   219→
   220→func (c *ControllerKeyWithAPIVersion) groupKind() (schema.GroupKind, error) {
   221→	// TODO: cache response
   222→	groupVersion, err := schema.ParseGroupVersion(c.ApiVersion)
   223→	if err != nil {
   224→		return schema.GroupKind{}, err
   225→	}
   226→
   227→	groupKind := schema.GroupKind{
   228→		Group: groupVersion.Group,
   229→		Kind:  c.Kind,
   230→	}
   231→
   232→	return groupKind, nil
   233→}
   234→
   235→func (f *controllerFetcher) isWellKnown(key *ControllerKeyWithAPIVersion) bool {
   236→	kind := wellKnownController(key.Kind)
   237→	_, exists := f.informersMap[kind]
   238→	return exists
   239→}
   240→
   241→func (f *controllerFetcher) getScaleForResource(ctx context.Context, namespace string, groupResource schema.GroupResource, name string) (controller *autoscalingapi.Scale, err error) {
   242→	if ok, scale, err := f.scaleSubresourceCacheStorage.Get(namespace, groupResource, name); ok {
   243→		return scale, err
   244→	}
   245→	scale, err := f.scaleNamespacer.Scales(namespace).Get(ctx, groupResource, name, metav1.GetOptions{})
   246→	f.scaleSubresourceCacheStorage.Insert(namespace, groupResource, name, scale, err)
   247→	return scale, err
   248→}
   249→
   250→func (f *controllerFetcher) isWellKnownOrScalable(ctx context.Context, key *ControllerKeyWithAPIVersion) bool {
   251→	if f.isWellKnown(key) {
   252→		return true
   253→	}
   254→
   255→	// if not well known check if it supports scaling
   256→	groupKind, err := key.groupKind()
   257→	if err != nil {
   258→		klog.ErrorS(err, "Could not find groupKind", "object", klog.KRef(key.Namespace, key.Name))
   259→		return false
   260→	}
   261→
   262→	if wellKnownController(groupKind.Kind) == node {
   263→		return false
   264→	}
   265→
   266→	mappings, err := f.mapper.RESTMappings(groupKind)
   267→	if err != nil {
   268→		klog.ErrorS(err, "Could not find mappings", "groupKind", groupKind, "object", klog.KRef(key.Namespace, key.Name))
   269→		return false
   270→	}
   271→
   272→	for _, mapping := range mappings {
   273→		groupResource := mapping.Resource.GroupResource()
   274→		scale, err := f.getScaleForResource(ctx, key.Namespace, groupResource, key.Name)
   275→		if err == nil && scale != nil {
   276→			return true
   277→		}
   278→	}
   279→	return false
   280→}
   281→
   282→func (f *controllerFetcher) getOwnerForScaleResource(ctx context.Context, groupKind schema.GroupKind, namespace, name string) (*ControllerKeyWithAPIVersion, error) {
   283→	if wellKnownController(groupKind.Kind) == node {
   284→		// Some pods specify nodes as their owners. This causes performance problems
   285→		// in big clusters when VPA tries to get all nodes. We know nodes aren't
   286→		// valid controllers so we can skip trying to fetch them.
   287→		return nil, ErrNodeInvalidOwner
   288→	}
   289→	mappings, err := f.mapper.RESTMappings(groupKind)
   290→	if err != nil {
   291→		return nil, err
   292→	}
   293→	var lastError error
   294→	for _, mapping := range mappings {
   295→		groupResource := mapping.Resource.GroupResource()
   296→		scale, err := f.getScaleForResource(ctx, namespace, groupResource, name)
   297→		if err == nil {
   298→			return getOwnerController(scale.OwnerReferences, namespace), nil
   299→		}
   300→		lastError = err
   301→	}
   302→
   303→	// nothing found, apparently the resource doesn't support scale (or we lack RBAC)
   304→	return nil, lastError
   305→}
   306→
   307→func (f *controllerFetcher) FindTopMostWellKnownOrScalable(ctx context.Context, key *ControllerKeyWithAPIVersion) (*ControllerKeyWithAPIVersion, error) {
   308→	if key == nil {
   309→		return nil, nil
   310→	}
   311→
   312→	var topMostWellKnownOrScalable *ControllerKeyWithAPIVersion
   313→
   314→	wellKnownOrScalable := f.isWellKnownOrScalable(ctx, key)
   315→	if wellKnownOrScalable {
   316→		topMostWellKnownOrScalable = key
   317→	}
   318→
   319→	visited := make(map[ControllerKeyWithAPIVersion]bool)
   320→	visited[*key] = true
   321→	for {
   322→		owner, err := f.getParentOfController(ctx, *key)
   323→		if err != nil {
   324→			return nil, err
   325→		}
   326→
   327→		if owner == nil {
   328→			return topMostWellKnownOrScalable, nil
   329→		}
   330→
   331→		wellKnownOrScalable = f.isWellKnownOrScalable(ctx, owner)
   332→		if wellKnownOrScalable {
   333→			topMostWellKnownOrScalable = owner
   334→		}
   335→
   336→		_, alreadyVisited := visited[*owner]
   337→		if alreadyVisited {
   338→			return nil, errors.New("cycle detected in ownership chain")
   339→		}
   340→		visited[*key] = true
   341→
   342→		key = owner
   343→	}
   344→}
